use super::consts::MS_OPTIONS;
use super::consts::OPTIONS;

pub(super) fn generate_option_combos() -> Vec<Vec<&'static str>> {
    let mut combos = Vec::new();

    // Baseline (no options)
    combos.push(vec![]);

    // Single options
    for opt in OPTIONS {
        combos.push(vec![opt.name]);
    }

    // Pairs
    for (i, opt_i) in OPTIONS.iter().enumerate() {
        for opt_j in &OPTIONS[i + 1..] {
            combos.push(vec![opt_i.name, opt_j.name]);
        }
    }

    // All options
    combos.push(OPTIONS.iter().map(|o| o.name).collect());

    combos
}

